module LDO_Regulator (  
    input wire clk,  
    input wire reset,  
    input wire [7:0] Vin,  
    input wire control,  
    output reg [7:0] Vout  
);  

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
    if (reset) begin  
        Vout <= 8'b0;  
    end else begin  
        if (control) begin  
            // Allow output to follow input  
            Vout <= Vin;  
        end else begin  
            // Regulate the output to a lower value (for simplicity, halve it)  
            Vout <= Vin >> 1;  
        end  
    end  
end  
endmodule
